"
"
;
}
std::cout <<
"\t(Decimal:
"
<< (
int
)count <<
")\n"
;
}
};
int
main() {
BinaryCounter3 my_counter;
std::cout <<
"Inicialización
del
contador:\n"
;
my_counter.display();
std::cout <<
"-------------------------------------------\n"
;
// Simulación de 10 ciclos de reloj consecutivos
for
(
int
cycle = 1; cycle <= 10; ++cycle) {
my_counter.clock_edge(
true
);
